<template>
  <div class="control-section visio-import-container">
    <div>
      <ejs-toolbar id="toolbar" ref="toolbar_diagram" overflowMode="Scrollable"
        style="width: 100%; height: 10%; margin-top: 10px" :clicked="toolbarclicked">
        <e-items>
          <e-item prefixIcon="e-icons e-circle-add" tooltipText="New Diagram" id="New_Diagram"></e-item>
          <e-item prefixIcon="e-icons e-import" tooltipText="Import Visio (.vsdx)" id="Import"></e-item>
          <e-item prefixIcon="e-icons e-export" tooltipText="Export as Visio (.vsdx)" id="Export"></e-item>
