          <e-item prefixIcon="e-cut e-icons" tooltipText="Cut" id="Cut" cssClass="tb-item-middle tb-item-lock-category"
            disabled="true"></e-item>
          <e-item prefixIcon="e-copy e-icons" tooltipText="Copy" id="Copy"
            cssClass="tb-item-middle tb-item-lock-category" disabled="true"></e-item>
          <e-item prefixIcon="e-icons e-paste" tooltipText="Paste" id="Paste" disabled="true"></e-item>
          <e-item type="Separator"></e-item>
          <e-item prefixIcon="e-icons e-undo" tooltipText="Undo" id="Undo" disabled="true"></e-item>
          <e-item prefixIcon="e-icons e-redo" tooltipText="Redo" id="Redo" disabled="true"></e-item>
          <e-item type="Separator"></e-item>
          <e-item disabled="true" prefixIcon="e-trash e-icons" tooltipText="Delete" id="Delete"
            cssClass="tb-item-middle tb-item-lock-category"></e-item>
          <e-item type="Separator"></e-item>
        </e-items>
      </ejs-toolbar>
    </div>
    <div style="width: 100%">
      <div class="sb-mobile-palette-bar">
        <div id="palette-icon-default" ref="paletteIcon" role="button" class="e-ddb-icons1 e-toggle-palette"></div>
      </div>
      <div id="palette-space" class="sb-mobile-palette" ref="paletteSpace">
        <ejs-symbolpalette id="symbolpalette" :expandMode="expandMode" :palettes="palettes"
          :width="palettewidth" :height="paletteheight" :getNodeDefaults="paletteNodeDefaults"
          :getConnectorDefaults="paletteConnectorDefaults" :getSymbolInfo="getSymbolInfo" :symbolHeight="symbolHeight"
          :symbolWidth="symbolWidth"></ejs-symbolpalette>
      </div>

      <div id="diagram-space" class="sb-mobile-diagram">
        <ejs-diagram style="display: block" ref="diagramObject" id="diagram" :width="width" :height="height"
          :nodes="nodes" :connectors="connectors" :diagramImporting="diagramImporting" :diagramExporting="diagramExporting"
          :selectionChange="selectionChange" :historyChange="historyChange" :dragEnter="dragEnter">
        </ejs-diagram>
      </div>
      <div>
        <ejs-toast ref="toastObj" :showCloseButton="true" :position="position" :timeOut="timeOut"></ejs-toast>
      </div>
      <div style="display: none">
        <input type="file" id="vsdxInput" ref="vsdxInput" accept=".vsdx,application/vnd.visio"/>
      </div>
    </div>
    <div id="action-description">
      <p>
        This sample demonstrates how to import and export Visio diagrams using the Syncfusion<sup>®</sup> EJ2 Vue Diagram. Any Visio file (.vsdx) can be imported to visualize and edit workflows, and the customized diagram can then be exported back to Visio format (.vsdx) for seamless collaboration and interoperability.
      </p>
      <p>
        <b>NOTE: This feature is currently experimental. Some functionalities may be limited or may not work as expected. We welcome you to try it out and share your <a href="https://www.syncfusion.com/feedback" target="_blank">feedback</a> as we continue to refine and improve it.</b>
      </p>
    </div>
    <div id="description">
      <p>
         The Visio file (.vsdx) can be imported through the "Import Visio" option in the toolbar using the <code>importFromVisio</code> method, and the customized file can be exported back to Visio format (.vsdx) through the "Export as Visio" option in the toolbar using the <code>exportToVisio</code> method. Once the file is imported, elements on the canvas can be edited using features such as <b>Cut</b>, <b>Copy</b>, <b>Paste</b>, <b>Drag</b>, <b>Resize</b>, <b>Delete</b>, <b>Draw Connectors and Shapes</b>, <b>Undo</b>, <b>Redo</b>, and other advanced options for complete customization.

        <br>

        Toast notifications are displayed during Visio file import and export operations to indicate statuses such as <b>started</b>, <b>completed</b>, or <b>failed</b>, using events like <code>diagramImporting</code> and <code>diagramExporting</code>.
      </p>
    </div>
  </div>
</template>
