<script>
import { createApp } from "vue";
import {
  DiagramComponent, SymbolPaletteComponent, Node,
  DiagramTools, BpmnDiagrams, UndoRedo, ImportAndExportVisio
} from "@syncfusion/ej2-vue-diagrams";
import { UploaderComponent } from "@syncfusion/ej2-vue-inputs";
import { ToolbarComponent, ItemsDirective, ItemDirective, } from "@syncfusion/ej2-vue-navigations";
import { SplitButtonComponent } from "@syncfusion/ej2-vue-splitbuttons";
import { ToastComponent } from '@syncfusion/ej2-vue-notifications';

let diagram;
let toolbarEditor;
let paletteSpace;
let paletteIcon;
let toast;
let uploader;

// Helper method to create a process node
function createNode(id, content, offsetY, shape = 'Process', offsetX = 400, width = 100, height = 50, ports = null) {
  const node = {
    id,
    shape: { type: 'Flow', shape },
    style: { fill: '#357BD2', strokeColor: 'white' },
    annotations: [{ content, style: { color: 'white' } }],
    offsetX,
    offsetY,
    width,
    height,
    ...(ports && { ports }),
  };
  return node;
}

// Helper method to create a connector
function createConnector(id, sourceID, targetID, annotation = null, sourcePortID = null, targetPortID = null) {
  return {
    id,
    sourceID,
    targetID,
    type: 'Orthogonal',
    ...(annotation && {
      annotations: [{
        content: annotation,
        alignment: annotation === 'Yes' ? 'After' : 'Before',
        displacement: annotation === 'Yes' ? { x: 5, y: 0 } : { x: 5, y: 5 },
      }],
    }),
    ...(sourcePortID && { sourcePortID }),
    ...(targetPortID && { targetPortID }),
  };
}

// Define the nodes using helper method
const nodes = [
  createNode('start', 'Start', 80, 'Terminator'),
  createNode('draft', 'Draft', 180, 'Process', 400, 100, 50, [
      { id: 'rightport', offset: { x: 1, y: 0.5 } },
  ]),
  createNode('approvedDecision', 'Approved?', 280, 'Decision', 400, 120, 60),
  createNode('revise', 'Revise', 280, 'Process', 600, 100, 50, [
      { id: 'rightport', offset: { x: 1, y: 0.5 } },
  ]),
  createNode('copyedit', 'Copyedit', 400),
  createNode('proof', 'Proof', 500),
  createNode('finalrevise', 'Revise', 600),
  createNode('finalize', 'Finalize', 700),
  createNode('publish', 'Publish', 800, 'Terminator')
];

// Define the connectors using helper method
const connectors = [
  createConnector('connector1', 'start', 'draft'),
  createConnector('connector2', 'draft', 'approvedDecision'),
  createConnector('connector3', 'approvedDecision', 'copyedit', 'Yes'),
  createConnector('connector4', 'approvedDecision', 'revise', 'No'),
  createConnector('connector5', 'revise', 'draft', undefined, 'rightport', 'rightport'),
  createConnector('connector6', 'copyedit', 'proof'),
  createConnector('connector7', 'proof', 'finalrevise'),
  createConnector('connector8', 'finalrevise', 'finalize'),
  createConnector('connector9', 'finalize', 'publish'),
];

//To handle drag events
function dragEnter(args) {
  let obj = args.element;
  if (obj instanceof Node) {
    let objWidth = obj.width;
    let objHeight = obj.height;
    let ratio = 100 / obj.width;
    obj.width = 100;
    obj.height *= ratio;
    obj.offsetX += (obj.width - objWidth) / 2;
    obj.offsetY += (obj.height - objHeight) / 2;
  }
}

// Define the palette nodes for "Flow Shapes"
const flowShapes = [
  { id: 'Process', shape: { type: 'Flow', shape: 'Process' } },
  { id: 'Decision', shape: { type: 'Flow', shape: 'Decision' } },
  { id: 'Document', shape: { type: 'Flow', shape: 'Document' } },
  { id: 'Terminator', shape: { type: 'Flow', shape: 'Terminator' } },
  { id: 'PreDefinedProcess', shape: { type: 'Flow', shape: 'PreDefinedProcess' } },
  { id: 'Data', shape: { type: 'Flow', shape: 'Data' } },
  { id: 'DirectData', shape: { type: 'Flow', shape: 'DirectData' } },
  { id: 'InternalStorage', shape: { type: 'Flow', shape: 'InternalStorage' } },
  { id: 'ManualInput', shape: { type: 'Flow', shape: 'ManualInput' } },
  { id: 'ManualOperation', shape: { type: 'Flow', shape: 'ManualOperation' } },
];

// Define the palette nodes for "Basic Shapes"
const basicShapes = [
  { id: 'Rectangle', shape: { type: 'Basic', shape: 'Rectangle' } },
  { id: 'Ellipse', shape: { type: 'Basic', shape: 'Ellipse' } },
  { id: 'Hexagon', shape: { type: 'Basic', shape: 'Hexagon' } },
  { id: 'Parallelogram', shape: { type: 'Basic', shape: 'Parallelogram' } },
  { id: 'Pentagon', shape: { type: 'Basic', shape: 'Pentagon' } },
  { id: 'Heptagon', shape: { type: 'Basic', shape: 'Heptagon' } },
  { id: 'Octagon', shape: { type: 'Basic', shape: 'Octagon' } },
  { id: 'Triangle', shape: { type: 'Basic', shape: 'Triangle' } },
  { id: 'Star', shape: { type: 'Basic', shape: 'Star' } },
  { id: 'Plus', shape: { type: 'Basic', shape: 'Plus' } },
];

// Define the palette connectors for "Connectors"
const paletteConnectors = [
  {
    id: 'Link1', type: 'Orthogonal',
    targetDecorator: { shape: 'Arrow', style: { strokeColor: '#757575', fill: '#757575' } },
  },
  {
    id: 'Link2', type: 'Orthogonal', sourcePoint: { x: 0, y: 0 }, targetPoint: { x: 60, y: 60 },
    targetDecorator: { shape: 'None' }
  },
  {
    id: 'Link3', type: 'Straight', sourcePoint: { x: 0, y: 0 }, targetPoint: { x: 60, y: 60 },
    targetDecorator: { shape: 'Arrow', style: { strokeColor: '#757575', fill: '#757575' } },
  },
  {
    id: 'Link4', type: 'Straight', sourcePoint: { x: 0, y: 0 }, targetPoint: { x: 60, y: 60 },
    targetDecorator: { shape: 'None' }
  },
  {
    id: 'Link5', type: 'Bezier', sourcePoint: { x: 0, y: 0 }, targetPoint: { x: 60, y: 60 },
    targetDecorator: { shape: 'None' }
  },
];
//To get default values for nodes in symbol palette
function paletteNodeDefaults(symbol) {
  symbol.style = { fill: '#357BD2', strokeColor: 'white' };
  symbol.width = 40;
  symbol.height = 40;
}
//To get default values for connectors in symbol palette
function paletteConnectorDefaults(connector) {
  connector.sourcePoint = { x: 0, y: 0 };
  connector.targetPoint = { x: 60, y: 60 };
}
function selectionChange(args) {
  if (args.state === 'Changed') {
    let selectedItems = diagram.selectedItems.nodes;
    selectedItems = selectedItems.concat(diagram.selectedItems.connectors);
    if (selectedItems.length === 0) {
      updateToolbarItems(['Cut', 'Copy', 'Delete'], true);
    }
    else {
      updateToolbarItems(['Cut', 'Copy', 'Delete'], false);
    }
  }
}
function historyChange() {
  updateToolbarItems(["Undo"], diagram.historyManager.undoStack.length === 0);
  updateToolbarItems(["Redo"], diagram.historyManager.redoStack.length === 0);
}

function diagramImporting(args) {
  toast.timeOut = 0;
  toast.showCloseButton = false;
  if (args.status === "started") {
    updateToolbarItems(['Export', 'Import'], true); // Disable buttons
    toast.hide();
    toast.timeOut = 1000;
    toast.title = 'Importing Diagram';
    toast.content = 'The Visio diagram is being imported. Please wait...';
    toast.cssClass = 'e-toast-info';
    toast.show();
  }
  else if (args.status === "completed") {
    toast.showCloseButton = true;
    toast.timeOut = 3000;
    toast.title = 'Import Complete';
    toast.content = 'The Visio diagram has been imported successfully.';
    toast.cssClass = 'e-toast-success';
    toast.show();
    updateToolbarItems(['Export', 'Import'], false); // Enable buttons
  }
  else if (args.status === "failed") {
    toast.showCloseButton = true;
    toast.timeOut = 3000;
    toast.title = 'Import Failed';
    toast.content = 'There was an error importing the Visio diagram.';
    toast.cssClass = 'e-toast-danger';
    toast.show();
    updateToolbarItems(['Export', 'Import'], false); // Enable buttons
  }
}
function diagramExporting(args) {
  toast.timeOut = 0;
  toast.showCloseButton = false;
  if (args.status === "started") {
    updateToolbarItems(['Export', 'Import'], true); // Disable buttons
    toast.hide();
    toast.timeOut = 1000;
    toast.title = 'Exporting Diagram';
    toast.content = 'The diagram is being exported to Visio format. Please wait...';
    toast.cssClass = 'e-toast-info';
    toast.show();
  }
  else if (args.status === "completed") {
    toast.showCloseButton = true;
    toast.timeOut = 3000;
    toast.title = 'Export Complete';
    toast.content = 'The diagram has been exported to Visio format successfully.';
    toast.cssClass = 'e-toast-success';
    toast.show();
    updateToolbarItems(['Export', 'Import'], false); // Enable buttons
  }
  else if (args.status === "failed") {
    toast.showCloseButton = true;
    toast.timeOut = 3000;
    toast.title = 'Export Failed';
    toast.content = 'There was an error exporting the diagram to Visio format.';
    toast.cssClass = 'e-toast-danger';
    toast.show();
    updateToolbarItems(['Export', 'Import'], false); // Enable buttons
  }
}

export default {
  components: {
    "ejs-diagram": DiagramComponent,
    "ejs-symbolpalette": SymbolPaletteComponent,
    "ejs-uploader": UploaderComponent,
    "ejs-toolbar": ToolbarComponent,
    "e-items": ItemsDirective,
    "e-item": ItemDirective,
    "ejs-splitbutton": SplitButtonComponent,
    "ejs-toast": ToastComponent
  },
  data: function () {
    return {
      width: "100%",
      height: "700px",
      nodes: nodes,
      connectors: connectors,
      diagramImporting: diagramImporting,
      diagramExporting: diagramExporting,
      dragEnter: dragEnter,
      expandMode: "Multiple",
      palettes: [
        {
          id: 'flowShapesPalette',
          expanded: true,
          symbols: flowShapes,
          title: 'Flow Shapes',
          iconCss: 'e-ddb-icons e-flow'
        },
        {
          id: 'basicShapesPalette',
          expanded: false,
          symbols: basicShapes,
          title: 'Basic Shapes',
          iconCss: 'e-ddb-icons e-basic'
        },
        {
          id: 'connectorsPalette',
          expanded: false,
          symbols: paletteConnectors,
          title: 'Connectors',
          iconCss: 'e-ddb-icons sf-diagram-icon-orthogonal'
        },
      ],
      palettewidth: "100%",
      paletteheight: "700px",
      symbolHeight: 50,
      symbolWidth: 50,
      paletteNodeDefaults: (symbol) => {
        return paletteNodeDefaults(symbol);
      },
      paletteConnectorDefaults: (symbol) => {
        return paletteConnectorDefaults(symbol);
      },
      getSymbolInfo: (symbol) => {
        return { fit: true };
      },

      //To handle tool bar clicks
      toolbarclicked: (args) => {
        let item = args.item.tooltipText;
        switch (item) {
          case "Undo":
            diagram.undo();
            break;
          case "Redo":
            diagram.redo();
            break;
          case "Cut":
            diagram.cut();
            updateToolbarItems(["Paste"], false);
            break;
          case "Copy":
            diagram.copy();
            updateToolbarItems(["Paste"], false);
            break;
          case "Paste":
            diagram.paste();
            break;
          case "Delete":
            diagram.remove();
            break;
          case "New Diagram":
            diagram.clear();
            historyChange();
            break;
          case "Export as Visio (.vsdx)":
            diagram.exportToVisio();
            break;
          case "Import Visio (.vsdx)":
            vsdxInput.click();
            break;
        }
      },
      //To enable and disable toolbar items based on selection changes
      selectionChange: selectionChange,
      // To Enable Undo Redo
      historyChange: historyChange,
      //To draw given connectors
      drawConnector: function () {
        return {
          template: createApp({}).component("drawConnector", {
            template:
              '<ejs-splitbutton cssClass="visio-import-container" :items ="conTypeItems" iconCss="sf-diagram-icon-orthogonal" :select="onConnectorSelect"></ejs-splitbutton>',
            components: {
              "ejs-splitbutton": SplitButtonComponent,
            },
            data() {
              return {
                conTypeItems: [
                  { text: "Straight", iconCss: "e-icons e-line" },
                  { text: "Orthogonal", iconCss: "sf-diagram-icon-orthogonal" },
                  { text: "Bezier", iconCss: "sf-diagram-icon-bezier" },
                ],
                onConnectorSelect: function (args) {
                  diagram.clearSelection();
                  diagram.drawingObject = { type: args.item.text };
                  diagram.tool = DiagramTools.DrawOnce;
                  diagram.dataBind();
                },
              };
            },
          }),
        };
      },
      //To draw given shapes
      drawShapes: function () {
        return {
          template: createApp({}).component("drawShapes", {
            template:
              '<ejs-splitbutton :items="shapesItems" iconCss="e-shapes e-icons" :select="onShapesSelect"></ejs-splitbutton>',
            components: {
              "ejs-splitbutton": SplitButtonComponent,
            },
            data() {
              return {
                shapesItems: [
                  { text: "Rectangle", iconCss: "e-rectangle e-icons" },
                  { text: "Ellipse", iconCss: "e-circle e-icons" },
                ],
                onShapesSelect: function (args) {
                  diagram.clearSelection();
                  diagram.drawingObject = {
                    shape: { type: 'Basic', shape: args.item.text },
                    style: { fill: '#357BD2', strokeColor: 'white' }
                  };
                  diagram.tool = DiagramTools.DrawOnce;
                  diagram.dataBind();
                },
              };
            },
          }),
        };
      },
      position: { X: 'Right', Y: 'Bottom' },
      timeOut: 0,
    };
  },
  provide: {
    diagram: [BpmnDiagrams, UndoRedo, ImportAndExportVisio],
  },
  mounted: function () {
    diagram = this.$refs.diagramObject.ej2Instances;
    toolbarEditor = this.$refs.toolbar_diagram.ej2Instances;
    toast = this.$refs.toastObj.ej2Instances;
    paletteIcon = this.$refs.paletteIcon;
    paletteSpace = this.$refs.paletteSpace;
    diagram.fitToPage();
    addEvents();
    // Add vsdxInput event listener
    if (this.$refs.vsdxInput) {
      this.$refs.vsdxInput.addEventListener('change', handleVsdxChange);
    }
  },
    beforeUnmount() {
      if (this.$refs.paletteIcon) {
        this.$refs.paletteIcon.removeEventListener('click', openPalette);
      }
      if (this.$refs.vsdxInput) {
        this.$refs.vsdxInput.removeEventListener('change', handleVsdxChange);
      }
    },
};

// Add this function instead:
async function handleVsdxChange(event) {
  if (!diagram) return;
  const file = event.target.files[0];
  if (!file) return;
  await diagram.importFromVisio(file);
  diagram.width = '100%';
  diagram.height = '700px';
  event.target.value = '';
}

// Enable or disable specific toolbar items
function updateToolbarItems(itemIds, disabled) {
  itemIds.forEach((itemId) => {
    const item = toolbarEditor.items.find((item) => item.id === itemId);
    if (item) {
      item.disabled = disabled;
    }
  });
}

//Adds EventListener based on device's viewport width.
function addEvents() {
  var isMobile = window.matchMedia("(max-width:550px)").matches;
  if (isMobile) {
    if (paletteIcon) {
      paletteIcon.addEventListener("click", openPalette, false);
    }
  }
}

//Toggles the visibility of the palette space on mobile devices when the palette icon is clicked.
function openPalette() {
  var isMobile = window.matchMedia("(max-width:550px)").matches;
  if (isMobile) {
    if (!paletteSpace.classList.contains("sb-mobile-palette-open")) {
      paletteSpace.classList.add("sb-mobile-palette-open");
    } else {
      paletteSpace.classList.remove("sb-mobile-palette-open");
    }
  }
}

</script>